  } catch {
    // keep detectedLanguage as &quot;en&quot;
  }
}

if (detectedLanguage !== &quot;en&quot;) {
  processText = await translateToEnglish(text, detectedLanguage);
  emit({ agent: &quot;Bridge&quot;, decision: &quot;translated&quot;, detail: `Detected ${detectedLanguage}, translated to English` });
